func computeInventoryHealth(db *sql.DB, minScore, maxScore int) ([]map[string]any, error) {
	rows, err := db.Query(`SELECT sku, asin, available, weeks_of_cover, sales_last_30_days, recommended_action, stranded_reason FROM inventory_planning`)
	if err != nil {
		return nil, err
	}
	defer rows.Close()
	var out []map[string]any
	for rows.Next() {
		var sku, asin, action, stranded sql.NullString
		var available, sales int
		var cover float64
		if err := rows.Scan(&sku, &asin, &available, &cover, &sales, &action, &stranded); err != nil {
			return nil, err
		}
		score, risks := inventoryHealthScore(cover, sales, available, action.String, stranded.String)
		if score < minScore || score > maxScore {
			continue
		}
		out = append(out, map[string]any{"sku": sku.String, "asin": asin.String, "health_score": score, "grade": scoreGrade(score), "weeks_of_cover": cover, "sell_through_rate": pct(float64(sales), float64(available+sales)), "available_qty": available, "recommended_action": action.String, "risk_factors": risks})
	}
	return out, rows.Err()
}

func inventoryHealthScore(weeksOfCover float64, salesLast30, available int, action, stranded string) (int, []string) {
	score := 100
	var risks []string
	if weeksOfCover < 2 {
		score -= 25
		risks = append(risks, "low_cover")
	} else if weeksOfCover > 12 {
		score -= 20
		risks = append(risks, "excess_cover")
	} else if weeksOfCover < 4 || weeksOfCover > 8 {
		score -= 10
		risks = append(risks, "outside_target_cover")
	}
	if salesLast30 == 0 && available > 0 {
		score -= 20
		risks = append(risks, "no_recent_sales")
	}
	if stranded != "" {
		score = 0
		risks = append(risks, "stranded")
	}
	if lowerContains(action, "remove") || lowerContains(action, "fix") {
		score -= 15
		risks = append(risks, "amazon_action_recommended")
	}
	if score < 0 {
		score = 0
	}
	return score, risks
}

func scoreGrade(score int) string {
	switch {
	case score >= 90:
		return "A"
	case score >= 80:
		return "B"
	case score >= 70:
		return "C"
	case score >= 60:
		return "D"
	default:
		return "F"
	}
}

func computeRestock(db *sql.DB, lead, safety, target int) ([]map[string]any, error) {
	rows, err := db.Query(`SELECT sku, asin, available, sales_last_30_days FROM inventory_planning`)
	if err != nil {
		return nil, err
	}
	defer rows.Close()
	var out []map[string]any
	for rows.Next() {
		var sku, asin sql.NullString
		var available, sales int
		if err := rows.Scan(&sku, &asin, &available, &sales); err != nil {
			return nil, err
		}
		velocity := float64(sales) / 30
		daysOut := 9999.0
		if velocity > 0 {
			daysOut = float64(available) / velocity
		}
		reorder := int(float64(lead+safety+target)*velocity) - available
		if reorder < 0 {
			reorder = 0
		}
		urgency := "ok"
		if daysOut <= float64(lead) {
			urgency = "critical"
		} else if daysOut <= float64(lead+safety) {
			urgency = "warning"
		}
		out = append(out, map[string]any{"sku": sku.String, "asin": asin.String, "available_qty": available, "daily_velocity": velocity, "days_until_stockout": daysOut, "reorder_qty": reorder, "urgency": urgency, "reorder_date": time.Now().AddDate(0, 0, int(daysOut)-lead).Format("2006-01-02")})
	}
	return out, rows.Err()
}

func computeAging(db *sql.DB, warnDays int) ([]map[string]any, error) {
	rows, err := db.Query(`SELECT i.sku, i.asin, i.available, i.days_in_fc, COALESCE(SUM(s.lts_12mo_fee),0), i.recommended_action FROM inventory_planning i LEFT JOIN storage_fees s ON s.sku=i.sku GROUP BY i.sku`)
	if err != nil {
		return nil, err
	}
	defer rows.Close()
	var out []map[string]any
	for rows.Next() {
		var sku, asin, action sql.NullString
		var available, days int
		var fee float64
		if err := rows.Scan(&sku, &asin, &available, &days, &fee, &action); err != nil {
			return nil, err
		}
		if days < warnDays && fee == 0 {
			continue
		}
		recommendation := "sell"
		if days >= 365 {
			recommendation = "remove"
		} else if days >= 181 {
			recommendation = "reduce price"
		}
		out = append(out, map[string]any{"sku": sku.String, "asin": asin.String, "available_qty": available, "days_in_fc": days, "days_until_181": maxInt(181-days, 0), "days_until_365": maxInt(365-days, 0), "estimated_lts_fee": fee, "recommended_action": firstNonEmpty(action.String, recommendation)})
	}
	return out, rows.Err()
}

func computeFBAvsFBM(db *sql.DB, shipCost float64) ([]map[string]any, error) {
	rows, err := db.Query(`SELECT sku, asin, COALESCE(your_price, sales_price, 0), COALESCE(referral_fee,0), COALESCE(fba_fulfillment_fee,0) + COALESCE(fba_pick_pack,0) + COALESCE(fba_weight_handling,0) + COALESCE(fba_order_handling,0) FROM fee_estimates`)
	if err != nil {
		return nil, err
	}
	defer rows.Close()
	var out []map[string]any
	for rows.Next() {
		var sku, asin sql.NullString
		var price, referral, fbaFee float64
		if err := rows.Scan(&sku, &asin, &price, &referral, &fbaFee); err != nil {
			return nil, err
		}
		fbaProfit := price - referral - fbaFee
		fbmProfit := price - referral - shipCost
		rec := "fba"
		if fbmProfit > fbaProfit {
			rec = "fbm"
		}
		out = append(out, map[string]any{"sku": sku.String, "asin": asin.String, "fba_profit_per_unit": fbaProfit, "fbm_estimated_profit_per_unit": fbmProfit, "recommendation": rec, "savings_per_unit": abs(fbmProfit - fbaProfit)})
	}
	return out, rows.Err()
}

func scanRowsMust(rows *sql.Rows, err error) (any, error) {
	if err != nil {
		return nil, err
	}
	return scanRows(rows)
}

func maxInt(a, b int) int {
	if a > b {
		return a
	}
	return b
}

